#!/bin/bash
# Uninstall script for Linphone
# Generated by IntuneBrew

# Exit on error
set -e

echo "Uninstalling Linphone..."

# Check if running as root
if [ "$EUID" -ne 0 ]; then
  echo "Please run as root"
  exit 1
fi

# Kill application process if running
echo "Stopping Linphone if running..."
pkill -f "Linphone" 2>/dev/null || true

# Remove /Applications/Linphone.app
echo "Removing /Applications/Linphone.app..."
if [ -d "/Applications/Linphone.app" ]; then
    rm -rf "/Applications/Linphone.app" 2>/dev/null || true
elif [ -f "/Applications/Linphone.app" ]; then
    rm -f "/Applications/Linphone.app" 2>/dev/null || true
fi

# Remove $HOME/Documents/linphone
echo "Removing $HOME/Documents/linphone..."
if [ -d "$HOME/Documents/linphone" ]; then
    rm -rf "$HOME/Documents/linphone" 2>/dev/null || true
elif [ -f "$HOME/Documents/linphone" ]; then
    rm -f "$HOME/Documents/linphone" 2>/dev/null || true
fi

# Remove $HOME/Library/Application Support/linphone
echo "Removing $HOME/Library/Application Support/linphone..."
if [ -d "$HOME/Library/Application Support/linphone" ]; then
    rm -rf "$HOME/Library/Application Support/linphone" 2>/dev/null || true
elif [ -f "$HOME/Library/Application Support/linphone" ]; then
    rm -f "$HOME/Library/Application Support/linphone" 2>/dev/null || true
fi

# Remove $HOME/Library/Preferences/com.belledonnecommunications.linphone.plist
echo "Removing $HOME/Library/Preferences/com.belledonnecommunications.linphone.plist..."
if [ -d "$HOME/Library/Preferences/com.belledonnecommunications.linphone.plist" ]; then
