fi

# Remove $HOME/Library/Preferences/com.linphone.linphone.plist
echo "Removing $HOME/Library/Preferences/com.linphone.linphone.plist..."
if [ -d "$HOME/Library/Preferences/com.linphone.linphone.plist" ]; then
    rm -rf "$HOME/Library/Preferences/com.linphone.linphone.plist" 2>/dev/null || true
elif [ -f "$HOME/Library/Preferences/com.linphone.linphone.plist" ]; then
    rm -f "$HOME/Library/Preferences/com.linphone.linphone.plist" 2>/dev/null || true
fi

# Remove $HOME/Library/Preferences/linphone
echo "Removing $HOME/Library/Preferences/linphone..."
if [ -d "$HOME/Library/Preferences/linphone" ]; then
    rm -rf "$HOME/Library/Preferences/linphone" 2>/dev/null || true
elif [ -f "$HOME/Library/Preferences/linphone" ]; then
