fi

# Remove $HOME/Library/Saved Application State/com.belledonnecommunications.linphone.savedState
echo "Removing $HOME/Library/Saved Application State/com.belledonnecommunications.linphone.savedState..."
if [ -d "$HOME/Library/Saved Application State/com.belledonnecommunications.linphone.savedState" ]; then
